#include <iostream>
using namespace std;

int main() {
    // Separate cout statements
    cout << "Name: Rohan" << endl;
    cout << "Age: 20" << endl;

    // Chaining multiple values in one cout
    cout << "Branch: " << "CSE" << ", Year: " << 3 << endl;

    // Mixing strings and expressions
    cout << "2 + 3 = " << 2 + 3 << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int age;
    string name;
    float gpa;

    cout << "Enter your name: ";
    cin >> name;

    cout << "Enter your age: ";
    cin >> age;

    cout << "Enter your GPA: ";
    cin >> gpa;

    cout << "\nHello, " << name << "!" << endl;
    cout << "Age: " << age << ", GPA: " << gpa << endl;

    return 0;
}

